<template><div class="center-page"><header class="heading"><div><el-tag round>Publisher Finance</el-tag><h1>收入与提现</h1><p>订单满14天可结算，每月1–7日可申请提现，最低 ¥100.00。</p></div><el-select v-model="organizationId" @change="load"><el-option v-for="o in organizations" :key="o.id" :label="o.display_name" :value="o.id"/></el-select></header><el-alert title="开发者应自行依法申报并缴纳相关税费；平台不承诺代扣代缴。" type="warning" show-icon :closable="false"/><section class="stats"><el-card><span>待结算</span><strong>{{ money(summary.pendingCents) }}</strong></el-card><el-card><span>可提现</span><strong>{{ money(summary.availableCents) }}</strong></el-card><el-card><span>已提现</span><strong>{{ money(summary.withdrawnCents) }}</strong></el-card><el-card><span>平台服务费</span><strong>{{ money(summary.platformFeeCents) }}</strong></el-card></section><el-card><h2>支付宝收款资料</h2><el-form inline><el-form-item label="收款人"><el-input v-model="recipient"/></el-form-item><el-form-item label="支付宝账号"><el-input v-model="account"/></el-form-item><el-button type="primary" @click="saveProfile">加密保存</el-button></el-form><el-divider/><h2>申请提现</h2><el-input-number v-model="amountYuan" :min="100" :precision="2"/><el-button class="action" type="primary" @click="withdraw">提交申请</el-button></el-card></div></template>
<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{ElMessage}from'element-plus';import{pluginCenterApi}from'@/api/pluginCenter';import{supabase}from'@/lib/supabase';
const organizations=ref<any[]>([]),organizationId=ref(''),recipient=ref(''),account=ref(''),amountYuan=ref(100);const summary=reactive({pendingCents:0,availableCents:0,withdrawnCents:0,platformFeeCents:0});const money=(v=0)=>`¥${(v/100).toFixed(2)}`;const load=async()=>{if(!organizationId.value)return;Object.assign(summary,await pluginCenterApi.getFinanceSummary(organizationId.value));};const saveProfile=async()=>{if(!recipient.value||!account.value)return ElMessage.warning('请填写完整资料');await pluginCenterApi.savePayoutProfile(organizationId.value,account.value,recipient.value);account.value='';recipient.value='';ElMessage.success('收款资料已加密保存');};const withdraw=async()=>{await pluginCenterApi.requestWithdrawal(organizationId.value,Math.round(amountYuan.value*100));ElMessage.success('提现申请已提交');await load();};onMounted(async()=>{const{data}=await supabase.from('plugin_center_publisher_organizations').select('id,display_name');organizations.value=data??[];organizationId.value=organizations.value[0]?.id??'';await load();});</script>
<style scoped lang="scss">.center-page{padding:4px}.heading{display:flex;justify-content:space-between;align-items:center;margin-bottom:20px}.heading h1{margin:10px 0 4px}.heading p{color:var(--el-text-color-secondary)}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin:20px 0}.stats span,.stats strong{display:block}.stats strong{font-size:25px;margin-top:10px}.action{margin-left:12px}@media(max-width:800px){.stats{grid-template-columns:1fr 1fr}.heading{align-items:flex-start;flex-direction:column}}</style>